<h1 class="h3 mb-1">Production Monitoring</h1><p class="text-muted mb-4">Current health indicators collected by the scheduled metrics job.</p><div class="row g-3 mb-4"><?php foreach($metrics as $m):?><div class="col-md-6 col-xl-3"><div class="card shadow-sm h-100"><div class="card-body"><div class="small text-uppercase text-muted"><?=e(str_replace('.',' ',$m['metric_key']))?></div><div class="display-6"><?=e($m['metric_value']!==null?round((float)$m['metric_value'],2):$m['metric_text'])?></div><span class="badge text-bg-<?=$m['status']==='ok'?'success':($m['status']==='warning'?'warning':($m['status']==='critical'?'danger':'secondary'))?>"><?=e($m['status'])?></span><div class="small text-muted mt-2"><?=e($m['measured_at'])?></div></div></div></div><?php endforeach?></div><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Recent Measurements</h2><div class="table-responsive"><table class="table"><thead><tr><th>Time</th><th>Metric</th><th>Value</th><th>Status</th></tr></thead><tbody><?php foreach($history as $h):?><tr><td><?=e($h['measured_at'])?></td><td><?=e($h['metric_key'])?></td><td><?=e($h['metric_value']??$h['metric_text'])?></td><td><?=e($h['status'])?></td></tr><?php endforeach?></tbody></table></div></div></div>
